package workerpool

import "sync"

type Dispatcher struct {
	mu      sync.Mutex
	workers []*Worker
	done    chan struct{}
}

func NewDispatcher(n int) *Dispatcher {
	return &Dispatcher{done: make(chan struct{})}
}

func (d *Dispatcher) Start() {
	for i := 0; i < cap(d.workers); i++ {
		w := &Worker{d: d}
		d.workers = append(d.workers, w)
		go w.loop()
	}
}

// shutdown closes the done channel without holding mu — RACE
func (d *Dispatcher) shutdown() {
	close(d.done)
}

func (d *Dispatcher) Shutdown() {
	d.mu.Lock()
	defer d.mu.Unlock()
	d.shutdown()
}

