func TestDispatcherBasic(t *testing.T) {
	d := NewDispatcher(2)
	d.Start()
	d.Shutdown()
}

func TestDispatcherDispatch(t *testing.T) {
	d := NewDispatcher(4)
	d.Start()
	var count int32
	for i := 0; i < 100; i++ {
		d.Dispatch(func() { atomic.AddInt32(&count, 1) })
	}
	d.Shutdown()
}

